import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import AdminUsers from '../components/Admin/AdminUsers';
import AdminRoles from '../components/Admin/AdminRoles';
import AdminAudit from '../components/Admin/AdminAudit';
import AdminSettings from '../components/Admin/AdminSettings';
import AdminOverview from '../components/Admin/AdminOverview';
import './Admin.css';

const ADMIN_NAV = [
  { icon: '⬡', label: 'Vue globale', id: 'overview' },
  { icon: '◈', label: 'Utilisateurs', id: 'users' },
  { icon: '◉', label: 'Rôles & Permissions', id: 'roles' },
  { icon: '▣', label: 'Audit Logs', id: 'audit' },
  { icon: '◎', label: 'Paramètres', id: 'settings' },
];

export default function Admin() {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('overview');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedFilters, setSelectedFilters] = useState({});
  const [refreshKey, setRefreshKey] = useState(0);

  const handleRefresh = () => {
    setRefreshKey(k => k + 1);
  };

  const handleFilterChange = (filterKey, value) => {
    setSelectedFilters(prev => ({
      ...prev,
      [filterKey]: value
    }));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'overview':
        return <AdminOverview key={refreshKey} />;
      case 'users':
        return <AdminUsers key={refreshKey} searchQuery={searchQuery} filters={selectedFilters} onRefresh={handleRefresh} />;
      case 'roles':
        return <AdminRoles key={refreshKey} onRefresh={handleRefresh} />;
      case 'audit':
        return <AdminAudit key={refreshKey} filters={selectedFilters} />;
      case 'settings':
        return <AdminSettings key={refreshKey} />;
      default:
        return <AdminOverview />;
    }
  };

  const renderFilters = () => {
    if (activeTab === 'users') {
      return (
        <div className="admin-filters">
          <input
            type="text"
            placeholder="Rechercher un utilisateur..."
            className="admin-filter-input"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <select
            className="admin-filter-select"
            value={selectedFilters.role || ''}
            onChange={(e) => handleFilterChange('role', e.target.value)}
          >
            <option value="">Tous les rôles</option>
            <option value="admin">Administrateur</option>
            <option value="assureur">Assureur</option>
            <option value="courtier">Courtier</option>
            <option value="client">Client</option>
          </select>
          <select
            className="admin-filter-select"
            value={selectedFilters.status || ''}
            onChange={(e) => handleFilterChange('status', e.target.value)}
          >
            <option value="">Tous les statuts</option>
            <option value="active">Actif</option>
            <option value="inactive">Inactif</option>
            <option value="suspended">Suspendu</option>
          </select>
        </div>
      );
    } else if (activeTab === 'audit') {
      return (
        <div className="admin-filters">
          <select
            className="admin-filter-select"
            value={selectedFilters.action || ''}
            onChange={(e) => handleFilterChange('action', e.target.value)}
          >
            <option value="">Toutes les actions</option>
            <option value="login">Connexion</option>
            <option value="create">Création</option>
            <option value="update">Modification</option>
            <option value="delete">Suppression</option>
          </select>
          <input
            type="date"
            className="admin-filter-select"
            value={selectedFilters.dateFrom || ''}
            onChange={(e) => handleFilterChange('dateFrom', e.target.value)}
          />
          <input
            type="date"
            className="admin-filter-select"
            value={selectedFilters.dateTo || ''}
            onChange={(e) => handleFilterChange('dateTo', e.target.value)}
          />
        </div>
      );
    }
    return null;
  };

  return (
    <div className="admin-container">
      {/* Header */}
      <div className="admin-header">
        <div className="admin-header-top">
          <h1 className="admin-title">Tableau de bord administrateur</h1>
          <p className="admin-subtitle">Gérez les utilisateurs, rôles, permissions et audit logs du système</p>
        </div>
        <div className="admin-header-actions">
          <button className="admin-btn admin-btn--primary" onClick={handleRefresh}>
            ↻ Actualiser
          </button>
        </div>
      </div>

      {/* Navigation Tabs */}
      <div className="admin-tabs">
        {ADMIN_NAV.map(item => (
          <button
            key={item.id}
            className={`admin-tab ${activeTab === item.id ? 'admin-tab--active' : ''}`}
            onClick={() => {
              setActiveTab(item.id);
              setSearchQuery('');
              setSelectedFilters({});
            }}
          >
            <span className="admin-tab-icon">{item.icon}</span>
            <span className="admin-tab-label">{item.label}</span>
          </button>
        ))}
      </div>

      {/* Filters */}
      {renderFilters()}

      {/* Content */}
      <div className="admin-content">
        {renderContent()}
      </div>
    </div>
  );
}
